INSERT INTO public.page_sections VALUES ('a62591b5-c21a-4573-8cae-53aac4f6a82f', 'about', 'hero', 'Hero', '{"image": "/hero/qatar-pearl.jpg", "title": "The quiet standard for premium living in Qatar.", "eyebrow": "About MaisonQatar", "description": "A Doha-based, licensed brokerage trusted by residents, executives and diplomats for over a decade. Hand-picked homes, principled advice, and a frictionless experience from first viewing to handover."}', 1, '2026-06-29 13:50:30.520819+00', '2026-06-29 13:50:30.520819+00', false) ON CONFLICT (id) DO NOTHING;
