INSERT INTO public.page_sections VALUES ('6042ef65-eb11-45a4-abd5-5fa54787acdd', 'about', 'content', 'About content', '{"team": {"title": "Meet the team", "eyebrow": "The people", "members": [{"bio": "12 years of luxury real estate experience across Doha and London.", "name": "Mariam Al-Thani", "role": "Founder & Principal Broker"}, {"bio": "Specialist in waterfront apartments and penthouse acquisitions.", "name": "Yusuf Rahman", "role": "Head of Sales · The Pearl & Lusail"}, {"bio": "Trusted by relocation teams at major Doha embassies and corporates.", "name": "Aisha Karim", "role": "Lettings Director · West Bay"}, {"bio": "Compound villas, family homes and long-tenure leases.", "name": "Khalid Mansour", "role": "Villa Specialist · Al Waab"}], "description": "A small, senior team of bilingual advisors — each a specialist in their corner of Qatar."}, "stats": [{"label": "Years in Qatar", "value": 12, "suffix": "+"}, {"label": "Properties closed", "value": 1400, "suffix": "+"}, {"label": "Client retention", "value": 94, "suffix": "%"}, {"label": "Premier areas covered", "value": 5, "suffix": ""}], "story": {"image": "", "title": "Founded in Doha. Built for residents who expect more.", "eyebrow": "Our story", "paragraphs": ["MaisonQatar was founded in 2013 with a simple thesis: Qatar''s premium real estate market deserved a brokerage that behaved like a private office, not a listings catalogue. We started with a single advisor in West Bay and a notebook of personally inspected addresses.", "A decade on, that discipline still defines us. We don''t chase volume. We work with a curated portfolio across The Pearl, Lusail, West Bay, Al Waab and inner Doha, and we stay with each client from the first viewing through handover, utilities, and — if it''s a lease — renewal.", "We''re proudly licensed in the State of Qatar, fluent in Arabic and English, and trusted by some of the country''s most discerning residents to find them a home worthy of the address."], "badge_title": "Est. 2013", "badge_subtitle": "West Bay · Doha"}, "values": {"items": [{"body": "Every listing is verified, every figure transparent. Our reputation in Qatar is built on what we don''t show as much as what we do.", "icon": "shield", "title": "Integrity first"}, {"body": "We personally inspect each residence before it joins the portfolio. If we wouldn''t live there, we won''t list it.", "icon": "sparkles", "title": "Hand-curated quality"}, {"body": "From first viewing to keys in hand, a dedicated agent handles your search — including bilingual paperwork and Qatari ID coordination.", "icon": "handshake", "title": "White-glove service"}, {"body": "Born in Doha, fluent in international expectations. We work with relocations from Europe, the GCC, and South Asia every week.", "icon": "globe", "title": "Local + global"}], "title": "Our values", "eyebrow": "What we stand for"}, "company": {"title": "Licensed. Local. Accountable.", "details": [{"label": "Legal name", "value": "MaisonQatar Real Estate Brokerage W.L.L."}, {"label": "License number", "value": "QA-RE-2013-08842"}, {"label": "Founded", "value": "2013, Doha"}, {"label": "Team size", "value": "24 specialists"}, {"label": "Head office", "value": "Tornado Tower, West Bay, Doha"}, {"label": "Languages", "value": "Arabic · English · Hindi · French"}, {"label": "Phone", "value": "+974 4000 0000"}, {"label": "Email", "value": "hello@maisonqatar.qa"}], "eyebrow": "Company details", "description": "Full company disclosure for clients, partners and regulators. Reach out any time — we''re happy to share additional documentation.", "primary_cta_label": "Explore listings", "secondary_cta_email": "hello@maisonqatar.qa", "secondary_cta_label": "Speak to an advisor"}, "mission": {"items": [{"tag": "Mission", "body": "We pair discerning residents and investors with the right address — handling every viewing, contract and key handover with the discretion the brief deserves.", "title": "Make premium living in Qatar effortless.", "points": ["Hand-verified listings only", "Bilingual, end-to-end concierge", "Transparent figures, no surprises"]}, {"tag": "Vision", "body": "To be the brokerage residents recommend by name — known across Doha, the GCC and beyond for taste, integrity, and an obsessive eye for the right home.", "title": "Define what luxury real estate looks like in the Gulf.", "points": ["Qatar''s most curated portfolio", "International standard, local soul", "A name passed between neighbours"]}], "title": "Our mission & vision", "eyebrow": "Purpose", "description": "The principles that shape every introduction, every viewing, and every handover — from The Pearl to Lusail Marina."}}', 2, '2026-06-29 14:05:28.964027+00', '2026-06-29 14:05:28.964027+00', false) ON CONFLICT (id) DO NOTHING;
